arguments.file_text:
@using sv_2d7fa07db6544fa9a1c71d7d6dfa8167.Models

<nav class="step-indicator" aria-label="Application steps">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i + 1;
        var isCurrent = step == CurrentStep;
        var isCompleted = CompletedSteps.Contains(step);
        var cssClass = isCurrent ? "step active" : isCompleted ? "step completed" : "step";

        <button class="@cssClass"
                disabled="@(!isCompleted && !isCurrent)"
                @onclick="() => OnStepClicked.InvokeAsync(step)"
                aria-current="@(isCurrent ? "step" : null)">
            <span class="step-number">
                @if (isCompleted && !isCurrent)
                {
                    <span class="checkmark">&#10003;</span>
                }
                else
                {
                    @step
                }
            </span>
            <span class="step-label">@StepNames[i]</span>
        </button>

        @if (i < StepNames.Length - 1)
        {
            <span class="step-connector @(CompletedSteps.Contains(step) ? "completed" : "")"></span>
        }
    }
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public HashSet<int> CompletedSteps { get; set; } = new();

    [Parameter, EditorRequired]
    public EventCallback<int> OnStepClicked { get; set; }
}

.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;
    margin-bottom: 2rem;
    flex-wrap: wrap;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.25rem;
    background: none;
    border: none;
    cursor: default;
    padding: 0.5rem;
    opacity: 0.4;
    transition: opacity 0.2s;
}

.step.active {
    opacity: 1;
}

.step.completed {
    opacity: 1;
    cursor: pointer;
}

.step.completed:hover .step-number {
    background-color: #0a58ca;
}

.step:disabled {
    cursor: default;
}

.step-number {
    width: 2.25rem;
    height: 2.25rem;
    border-radius: 50%;
    background-color: #6c757d;
    color: white;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
}

.step.active .step-number {
    background-color: #0d6efd;
}

.step.completed .step-number {
    background-color: #198754;
}

.checkmark {
    font-size: 1rem;
}

.step-label {
    font-size: 0.75rem;
    color: #495057;
    white-space: nowrap;
}

.step.active .step-label {
    font-weight: 600;
    color: #0d6efd;
}

.step-connector {
    width: 2rem;
    height: 2px;
    background-color: #dee2e6;
    margin-bottom: 1.25rem;
}

.step-connector.completed {
    background-color: #198754;
}

