@using sv_2d7fa07db6544fa9a1c71d7d6dfa8167.Models

<nav class="step-indicator" aria-label="Application steps">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i + 1;
        var isCurrent = step == CurrentStep;
        var isCompleted = CompletedSteps.Contains(step);
        var cssClass = isCurrent ? "step active" : isCompleted ? "step completed" : "step";

        <button class="@cssClass"
                disabled="@(!isCompleted && !isCurrent)"
                @onclick="() => OnStepClicked.InvokeAsync(step)"
                aria-current="@(isCurrent ? "step" : null)">
            <span class="step-number">
                @if (isCompleted && !isCurrent)
                {
                    <span class="checkmark">&#10003;</span>
                }
                else
                {
                    @step
                }
            </span>
            <span class="step-label">@StepNames[i]</span>
        </button>

        @if (i < StepNames.Length - 1)
        {
            <span class="step-connector @(CompletedSteps.Contains(step) ? "completed" : "")"></span>
        }
    }
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public HashSet<int> CompletedSteps { get; set; } = new();

    [Parameter, EditorRequired]
    public EventCallback<int> OnStepClicked { get; set; }
}

