@using sv_2d7fa07db6544fa9a1c71d7d6dfa8167.Models

<h4 class="mb-4">Personal Information</h4>

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.FullName" @bind:event="oninput" placeholder="Your full name" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(EmailError is not null ? "is-invalid" : "")"
               @bind="Model.Email" @bind:event="oninput" placeholder="your@email.com" />
        @if (EmailError is not null)
        {
            <div class="invalid-feedback">@EmailError</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" placeholder="Phone number" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.Address" @bind:event="oninput" placeholder="Your address" />
    </div>
</div>

@if (ValidationError is not null)
{
    <div class="alert alert-danger mt-3">@ValidationError</div>
}

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter]
    public string? EmailError { get; set; }

    [Parameter]
    public EventCallback<string?> EmailErrorChanged { get; set; }

    [Parameter, EditorRequired]
    public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ValidationError;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ValidationError = null;
        await EmailErrorChanged.InvokeAsync(null);

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            ValidationError = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var isValid = await ValidateEmail(Model.Email);
            if (!isValid)
            {
                await EmailErrorChanged.InvokeAsync("This email address is not valid.");
                return;
            }
        }
        finally
        {
            IsValidating = false;
        }

        await OnNext.InvokeAsync();
    }
}

